15	export class ProcessResponseService {
16	  constructor(
17	    private readonly platformStore: PlatformStore,
18	    private readonly processAccessService: ProcessAccessService,
19	  ) {}
20	
21	  async respond(args: {
22	    actor: AuthenticatedActor;
23	    projectId: string;
24	    processId: string;
25	    body: unknown;
26	  }): Promise<SubmitProcessResponseResponse> {
27	    const access = await this.processAccessService.assertProcessAccess(args);
28	    const parsedBody = submitProcessResponseRequestSchema.safeParse(args.body);
29	
30	    if (!parsedBody.success) {
31	      throw new AppError({
32	        code: 'INVALID_PROCESS_RESPONSE',
33	        message: 'Submitted response must include a non-empty clientRequestId and message.',
34	        statusCode: 422,
35	      });
36	    }
37	
38	    const normalizedRequest = this.normalizeRequest(parsedBody.data);
39	    const existing = await this.platformStore.getSubmittedProcessResponse({
40	      processId: access.process.processId,
41	      clientRequestId: normalizedRequest.clientRequestId,
42	    });
43	
44	    if (existing !== null) {
45	      return submitProcessResponseResponseSchema.parse({
46	        accepted: true,
47	        historyItemId: existing.historyItem.historyItemId,
48	        process: buildProcessSurfaceSummary(existing.process),
49	        currentRequest: existing.currentRequest,
50	      });
51	    }
52	
53	    if (!access.process.availableActions.includes('respond')) {
54	      throw new AppError({
55	        code: 'PROCESS_ACTION_NOT_AVAILABLE',
56	        message: 'Respond is not available for this process right now.',
57	        statusCode: 409,
58	      });
59	    }
60	
61	    try {
62	      const result = await this.platformStore.submitProcessResponse({
63	        processId: access.process.processId,
64	        ...normalizedRequest,
65	      });
66	
67	      return submitProcessResponseResponseSchema.parse({
68	        accepted: true,
69	        historyItemId: result.historyItem.historyItemId,
70	        process: buildProcessSurfaceSummary(result.process),
71	        currentRequest: result.currentRequest,
72	      });
73	    } catch (_error) {
74	      throw new AppError({
75	        code: 'PROCESS_ACTION_FAILED',
76	        message:
77	          'The process response could not be completed right now. Try again or reload the page.',
78	        statusCode: 500,
79	      });
80	    }
81	  }
