259	export const submitProcessResponse = mutation({
260	  args: {
261	    processId: v.string(),
262	    clientRequestId: v.string(),
263	    message: v.string(),
264	  },
265	  handler: async (
266	    ctx,
267	    args,
268	  ): Promise<{
269	    accepted: true;
270	    historyItem: ProcessHistoryItem;
271	    process: ProcessSummary;
272	    currentRequest: CurrentProcessRequest | null;
273	  }> => {
274	    let processRecord: Doc<'processes'> | null = null;
275	
276	    try {
277	      processRecord = await ctx.db.get(args.processId as Id<'processes'>);
278	    } catch {
279	      throw new Error('Process not found.');
280	    }
281	
282	    if (processRecord === null) {
283	      throw new Error('Process not found.');
284	    }
285	
286	    const trimmedClientRequestId = args.clientRequestId.trim();
287	    const trimmedMessage = args.message.trim();
288	
289	    if (trimmedClientRequestId.length === 0 || trimmedMessage.length === 0) {
290	      throw new Error('Invalid process response.');
291	    }
292	
293	    const existingHistoryItem = await ctx.db
294	      .query('processHistoryItems')
295	      .withIndex('by_processId_and_clientRequestId', (indexQuery) =>
296	        indexQuery.eq('processId', processRecord._id).eq('clientRequestId', trimmedClientRequestId),
297	      )
298	      .unique();
299	
300	    if (existingHistoryItem !== null) {
301	      return {
302	        accepted: true,
303	        historyItem: buildProcessHistoryItem(existingHistoryItem),
304	        process: buildProcessSummary(processRecord),
305	        currentRequest: await resolveCurrentProcessRequest(ctx, processRecord),
306	      };
307	    }
308	
309	    const now = new Date().toISOString();
310	
311	    if (processRecord.currentRequestHistoryItemId !== null) {
312	      const currentRequestHistoryItem = await ctx.db.get(processRecord.currentRequestHistoryItemId);
313	
314	      if (currentRequestHistoryItem !== null) {
315	        await ctx.db.patch(currentRequestHistoryItem._id, {
316	          lifecycleState: 'finalized',
317	          requestState: 'resolved',
318	          finalizedAt: now,
319	        });
320	      }
321	    }
322	
323	    const historyItemId = await ctx.db.insert('processHistoryItems', {
324	      processId: processRecord._id,
325	      kind: 'user_message',
326	      lifecycleState: 'finalized',
327	      requestState: 'none',
328	      text: trimmedMessage,
329	      relatedSideWorkId: null,
330	      relatedArtifactId: null,
331	      clientRequestId: trimmedClientRequestId,
332	      createdAt: now,
333	      finalizedAt: now,
334	    });
335	
336	    const nextProcessFields = {
337	      status: 'running' as const,
338	      nextActionLabel: 'Monitor progress in the work surface',
339	      currentRequestHistoryItemId: null,
340	      updatedAt: now,
341	    };
342	
343	    await ctx.db.patch(processRecord._id, nextProcessFields);
344	
345	    try {
346	      await ctx.db.patch(processRecord.projectId as Id<'projects'>, {
347	        lastUpdatedAt: now,
348	        updatedAt: now,
349	      });
350	    } catch {
351	      // Keep the accepted response durable even if the project lookup is stale.
352	    }
353	
354	    const historyItem = await ctx.db.get(historyItemId);
355	
356	    if (historyItem === null) {
357	      throw new Error('Accepted process response history item was not found.');
358	    }
359	
360	    return {

361	      accepted: true,
362	      historyItem: buildProcessHistoryItem(historyItem),
363	      process: buildProcessSummary({
364	        ...processRecord,
365	        ...nextProcessFields,
366	      }),
367	      currentRequest: null,
368	    };
369	  },
370	});
