398	async function resolveCurrentProcessRequest(
399	  ctx: MutationCtx | QueryCtx,
400	  processRecord: Doc<'processes'>,
401	): Promise<CurrentProcessRequest | null> {
402	  if (processRecord.currentRequestHistoryItemId === null) {
403	    return null;
404	  }
405	
406	  const historyItem = await ctx.db.get(processRecord.currentRequestHistoryItemId);
407	
408	  if (
409	    historyItem === null ||
410	    historyItem.processId !== processRecord._id ||
411	    historyItem.kind !== 'attention_request' ||
412	    historyItem.requestState !== 'unresolved'
413	  ) {
414	    return null;
415	  }
416	
417	  return {
418	    requestId: historyItem._id,
419	    requestKind: 'other',
420	    promptText: historyItem.text,
421	    requiredActionLabel: processRecord.nextActionLabel,
422	    createdAt: historyItem.createdAt,
423	  };
424	}
