426	function deriveAvailableActions(status: ProcessStatus): ProcessAvailableAction[] {
427	  switch (status) {
428	    case 'draft':
429	      return ['open'];
430	    case 'running':
431	      return ['open', 'review'];
432	    case 'waiting':
433	      return ['respond'];
434	    case 'paused':
435	      return ['resume'];
436	    case 'completed':
437	      return ['review'];
438	    case 'failed':
439	      return ['review', 'restart'];
440	    case 'interrupted':
441	      return ['resume', 'review', 'rehydrate', 'restart'];
442	    default:
443	      return [];
444	  }
445	}
