 23	function buildFallbackRequestError(response: Response): RequestError {
 24	  switch (response.status) {
 25	    case 401:
 26	      return {
 27	        code: 'UNAUTHENTICATED',
 28	        message: 'Authenticated access is required.',
 29	        status: 401,
 30	      };
 31	    case 403:
 32	      return {
 33	        code: 'PROJECT_FORBIDDEN',
 34	        message: 'You do not have access to this process.',
 35	        status: 403,
 36	      };
 37	    case 404:
 38	      return {
 39	        code: 'PROCESS_NOT_FOUND',
 40	        message: 'The requested process could not be found.',
 41	        status: 404,
 42	      };
 43	    case 409:
 44	      return {
 45	        code: 'PROCESS_ACTION_NOT_AVAILABLE',
 46	        message: 'This process action is not available right now.',
 47	        status: 409,
 48	      };
 49	    case 422:
 50	      return {
 51	        code: 'INVALID_PROCESS_RESPONSE',
 52	        message: 'Submitted response must include a non-empty clientRequestId and message.',
 53	        status: 422,
 54	      };
 55	    default:
 56	      return {
 57	        code: 'PROCESS_ACTION_FAILED',
 58	        message:
 59	          'The process action could not be completed right now. Try again or reload the page.',
 60	        status: response.status >= 400 ? response.status : 500,
 61	      };
 62	  }
 63	}
 64	
 65	async function parseRequestError(response: Response) {
 66	  const body = await response.json().catch(() => null);
 67	  const parsed = requestErrorSchema.safeParse(body);
 68	
 69	  if (parsed.success) {
 70	    return parsed.data;
 71	  }
 72	
 73	  return buildFallbackRequestError(response);
 74	}
