 89	      });
 90	      notify();
 91	    },
 92	    subscribe(listener): () => void {
 93	      listeners.add(listener);
 94	
 95	      return () => {
 96	        listeners.delete(listener);
 97	      };
 98	    },
 99	  };
100	}

